    if !error_groups.is_empty() {
        println!("\nErrors:");
        let mut groups: Vec<_> = error_groups.into_iter().collect();
        groups.sort_by(|a, b| b.1.count.cmp(&a.1.count));
        for (key, group) in &groups {
            println!(
                "  {}x {} in {} ({}:{} in {} file(s))",
                group.count,
                key.message,
                key.record_type,
                group.example_file,
                group.example_line,
                group.file_count,
            );
